static int32_t copy_special_str(char *const result,
                            const bool sign,
                            const bool exponent,
                            const bool mantissa)
{
    if (mantissa)
    {
        rmemcpy1(result, 0, "NaN", 3);
        return 3;
    }
    if (sign)
    {
        result[0] = '-';
    }
    if (exponent)
    {
        rmemcpy1(result + sign, 0, "Infinity", 8);
        return sign + 8;
    }
    result[sign] = '0';
    return sign + 1;
}

static bool f2d_small_int(const uint32_t ieeeMantissa,
                          const uint32_t ieeeExponent,
                          floating_decimal_32 *v)
{
    const int32_t e2 = (int32_t) ieeeExponent - FLOAT_BIAS - FLOAT_MANTISSA_BITS;

    /*
     * Avoid using multiple "return false;" here since it tends to provoke the
     * compiler into inlining multiple copies of f2d, which is undesirable.
     */

    if (e2 >= -FLOAT_MANTISSA_BITS && e2 <= 0)
    {
        /*----
         * Since 2^23 <= m2 < 2^24 and 0 <= -e2 <= 23:
         *   1 <= f = m2 / 2^-e2 < 2^24.
         *
         * Test if the lower -e2 bits of the significand are 0, i.e. whether
         * the fraction is 0. We can use ieeeMantissa here, since the implied
         * 1 bit can never be tested by this; the implied 1 can only be part
         * of a fraction if e2 < -FLOAT_MANTISSA_BITS which we already
         * checked. (e.g. 0.5 gives ieeeMantissa == 0 and e2 == -24)
         */
        const uint32_t mask = (1U << -e2) - 1;
        const uint32_t fraction = ieeeMantissa & mask;

        if (fraction == 0)
        {
            /*----
             * f is an integer in the range [1, 2^24).
             * Note: mantissa might contain trailing (decimal) 0's.
             * Note: since 2^24 < 10^9, there is no need to adjust
             * decimalLength().
             */
            const uint32_t m2 = (1U << FLOAT_MANTISSA_BITS) | ieeeMantissa;

            v->mantissa = m2 >> -e2;
            v->exponent = 0;
            return true;
        }
    }

    return false;
}

/*  Returns floor(log_10(2^e)). */
static int32_t log10Pow2(const int32_t e)
{
    /*
     * The first value this approximation fails for is 2^1651 which is just
     * greater than 10^297.
     */

    return (int32_t) ((((uint32_t) e) * 78913) >> 18);
}

/*  Returns e == 0 ? 1 : ceil(log_2(5^e)). */
static uint32_t pow5bits(const int32_t e)
{
    /*
     * This approximation works up to the point that the multiplication
     * overflows at e = 3529.
     *
     * If the multiplication were done in 64 bits, it would fail at 5^4004
     * which is just greater than 2^9297.
     */
    return ((((uint32_t) e) * 1217359) >> 19) + 1;
}

/*
 * It seems to be slightly faster to avoid uint128_t here, although the
 * generated code for uint128_t looks slightly nicer.
 */
static uint32_t mulShift32(const uint32_t m, const uint64_t factor, const int32_t shift)
{
    /*
     * The casts here help MSVC to avoid calls to the __allmul library
     * function.
     */
    const uint32_t factorLo = (uint32_t) (factor);
    const uint32_t factorHi = (uint32_t) (factor >> 32);
    const uint64_t bits0 = (uint64_t) m * factorLo;
    const uint64_t bits1 = (uint64_t) m * factorHi;

#if 0
    /*
     * On 32-bit platforms we can avoid a 64-bit shift-right since we only
     * need the upper 32 bits of the result and the shift value is > 32.
     */
    const uint32_t bits0Hi = (uint32_t) (bits0 >> 32);
    uint32_t        bits1Lo = (uint32_t) (bits1);
    uint32_t        bits1Hi = (uint32_t) (bits1 >> 32);

    bits1Lo += bits0Hi;
    bits1Hi += (bits1Lo < bits0Hi);

    const int32_t s = shift - 32;

    return (bits1Hi << (32 - s)) | (bits1Lo >> s);

#else/* RYU_32_BIT_PLATFORM */

    const uint64_t sum = (bits0 >> 32) + bits1;
    const uint64_t shiftedSum = sum >> (shift - 32);

    return (uint32_t) shiftedSum;

#endif/* RYU_32_BIT_PLATFORM */
}

static uint32_t mulPow5InvDivPow2(const uint32_t m, const uint32_t q, const int32_t j)
{
    return mulShift32(m, FLOAT_POW5_INV_SPLIT[q], j);
}

static uint32_t pow5Factor(uint32_t value)
{
    uint32_t count = 0;

    for (;;)
    {
        const uint32_t q = value / 5;
        const uint32_t r = value % 5;

        if (r != 0)
            break;

        value = q;
        ++count;
    }
    return count;
}

static bool multipleOfPowerOf5(const uint32_t value, const uint32_t p)
{
    return pow5Factor(value) >= p;
}

/*  Returns floor(log_10(5^e)). */
static int32_t log10Pow5(const int32_t e)
{
    /*
     * The first value this approximation fails for is 5^2621 which is just
     * greater than 10^1832.
     */
    return (int32_t) ((((uint32_t) e) * 732923) >> 20);
}

static uint32_t mulPow5divPow2(const uint32_t m, const uint32_t i, const int32_t j)
{
    return mulShift32(m, FLOAT_POW5_SPLIT[i], j);
}

/*  Returns true if value is divisible by 2^p. */
static bool multipleOfPowerOf2(const uint32_t value, const uint32_t p)
{
    /* return __builtin_ctz(value) >= p; */
    return (value & ((1u << p) - 1)) == 0;
}

static floating_decimal_32 f2d(const int32_t ieeeMantissa, const int32_t ieeeExponent)
{
    int32_t        e2 = (ieeeExponent == 0 ? 1 - FLOAT_BIAS - FLOAT_MANTISSA_BITS - 2 : ieeeExponent - FLOAT_BIAS - FLOAT_MANTISSA_BITS - 2);
    int32_t        m2 = (ieeeExponent == 0 ? ieeeMantissa : (1u << FLOAT_MANTISSA_BITS) | ieeeMantissa);

#if STRICTLY_SHORTEST
    const bool    even = (m2 & 1) == 0;
    const bool    acceptBounds = even;
#else
    const bool    acceptBounds = false;
#endif

    /* Step 2: Determine the interval of legal decimal representations. */
    const int32_t mv = 4 * m2;
    const int32_t mp = 4 * m2 + 2;

    /* Implicit bool -> int32_t conversion. True is 1, false is 0. */
    const int32_t mmShift = ieeeMantissa != 0 || ieeeExponent <= 1;
    const int32_t mm = 4 * m2 - 1 - mmShift;

    /* Step 3: Convert to a decimal power base using 64-bit arithmetic. */
    int32_t        vr,
                vp,
                vm;
    int32_t        e10;
    bool        vmIsTrailingZeros = false;
    bool        vrIsTrailingZeros = false;
    uint8_t        lastRemovedDigit = 0;
    int32_t        removed = 0;
    int32_t        output;
    floating_decimal_32 fd;

    if (e2 >= 0)
    {
        const int32_t q = log10Pow2(e2);

        const int32_t k = FLOAT_POW5_INV_BITCOUNT + pow5bits(q) - 1;
        const int32_t i = -e2 + q + k;
        e10 = q;

        vr = mulPow5InvDivPow2(mv, q, i);
        vp = mulPow5InvDivPow2(mp, q, i);
        vm = mulPow5InvDivPow2(mm, q, i);

        if (q != 0 && (vp - 1) / 10 <= vm / 10)
        {
            /*
             * We need to know one removed digit even if we are not going to
             * loop below. We could use q = X - 1 above, except that would
             * require 33 bits for the result, and we've found that 32-bit
             * arithmetic is faster even on 64-bit machines.
             */
            const int32_t l = FLOAT_POW5_INV_BITCOUNT + pow5bits(q - 1) - 1;

            lastRemovedDigit = (uint8_t) (mulPow5InvDivPow2(mv, q - 1, -e2 + q - 1 + l) % 10);
        }
        if (q <= 9)
        {
            /*
             * The largest power of 5 that fits in 24 bits is 5^10, but q <= 9
             * seems to be safe as well.
             *
             * Only one of mp, mv, and mm can be a multiple of 5, if any.
             */
            if (mv % 5 == 0)
            {
                vrIsTrailingZeros = multipleOfPowerOf5(mv, q);
            }
            else if (acceptBounds)
            {
                vmIsTrailingZeros = multipleOfPowerOf5(mm, q);
            }
            else
            {
                vp -= multipleOfPowerOf5(mp, q);
            }
        }
    }
    else
    {
        const int32_t q = log10Pow5(-e2);

        const int32_t i = -e2 - q;
        const int32_t k = pow5bits(i) - FLOAT_POW5_BITCOUNT;
        int32_t        j = q - k;

        e10 = q + e2;

        vr = mulPow5divPow2(mv, i, j);
        vp = mulPow5divPow2(mp, i, j);
        vm = mulPow5divPow2(mm, i, j);

        if (q != 0 && (vp - 1) / 10 <= vm / 10)
        {
            j = q - 1 - (pow5bits(i + 1) - FLOAT_POW5_BITCOUNT);
            lastRemovedDigit = (uint8_t) (mulPow5divPow2(mv, i + 1, j) % 10);
        }
        if (q <= 1)
        {
            /*
             * {vr,vp,vm} is trailing zeros if {mv,mp,mm} has at least q
             * trailing 0 bits.
             */
            /* mv = 4 * m2, so it always has at least two trailing 0 bits. */
            vrIsTrailingZeros = true;
            if (acceptBounds)
            {
                /*
                 * mm = mv - 1 - mmShift, so it has 1 trailing 0 bit iff
                 * mmShift == 1.
                 */
                vmIsTrailingZeros = mmShift == 1;
            }
            else
            {
                /*
                 * mp = mv + 2, so it always has at least one trailing 0 bit.
                 */
                --vp;
            }
        }
        else if (q < 31)
        {
            /* TODO(ulfjack):Use a tighter bound here. */
            vrIsTrailingZeros = multipleOfPowerOf2(mv, q - 1);
        }
    }

    /*
     * Step 4: Find the shortest decimal representation in the interval of
     * legal representations.
     */

    if (vmIsTrailingZeros || vrIsTrailingZeros)
    {
        /* General case, which happens rarely (~4.0%). */
        while (vp / 10 > vm / 10)
        {
            vmIsTrailingZeros &= vm - (vm / 10) * 10 == 0;
            vrIsTrailingZeros &= lastRemovedDigit == 0;
            lastRemovedDigit = (uint8_t) (vr % 10);
            vr /= 10;
            vp /= 10;
            vm /= 10;
            ++removed;
        }
        if (vmIsTrailingZeros)
        {
            while (vm % 10 == 0)
            {
                vrIsTrailingZeros &= lastRemovedDigit == 0;
                lastRemovedDigit = (uint8_t) (vr % 10);
                vr /= 10;
                vp /= 10;
                vm /= 10;
                ++removed;
            }
        }

        if (vrIsTrailingZeros && lastRemovedDigit == 5 && vr % 2 == 0)
        {
            /* Round even if the exact number is .....50..0. */
            lastRemovedDigit = 4;
        }

        /*
         * We need to take vr + 1 if vr is outside bounds or we need to round
         * up.
         */
        output = vr + ((vr == vm && (!acceptBounds || !vmIsTrailingZeros)) || lastRemovedDigit >= 5);
    }
    else
    {
        /*
         * Specialized for the common case (~96.0%). Percentages below are
         * relative to this.
         *
         * Loop iterations below (approximately): 0: 13.6%, 1: 70.7%, 2:
         * 14.1%, 3: 1.39%, 4: 0.14%, 5+: 0.01%
         */
        while (vp / 10 > vm / 10)
        {
            lastRemovedDigit = (uint8_t) (vr % 10);
            vr /= 10;
            vp /= 10;
            vm /= 10;
            ++removed;
        }

        /*
         * We need to take vr + 1 if vr is outside bounds or we need to round
         * up.
         */
        output = vr + (vr == vm || lastRemovedDigit >= 5);
    }

    do
    {
        const int32_t exp = e10 + removed;
        fd.exponent = exp;
        fd.mantissa = output;
    } while (0);

    return fd;
}

static uint32_t decimalLength(const uint64_t v)
{
    /* This is slightly faster than a loop. */
    /* The average output length is 16.38 digits, so we check high-to-low. */
    /* Function precondition: v is not an 18, 19, or 20-digit number. */
    /* (17 digits are sufficient for round-tripping.) */
    if (v >= 10000000000000000L)
    {
        return 17;
    }
    if (v >= 1000000000000000L)
    {
        return 16;
    }
    if (v >= 100000000000000L)
    {
        return 15;
    }
    if (v >= 10000000000000L)
    {
        return 14;
    }
    if (v >= 1000000000000L)
    {
        return 13;
    }
    if (v >= 100000000000L)
    {
        return 12;
    }
    if (v >= 10000000000L)
    {
        return 11;
    }
    if (v >= 1000000000L)
    {
        return 10;
    }
    if (v >= 100000000L)
    {
        return 9;
    }
    if (v >= 10000000L)
    {
        return 8;
    }
    if (v >= 1000000L)
    {
        return 7;
    }
    if (v >= 100000L)
    {
        return 6;
    }
    if (v >= 10000L)
    {
        return 5;
    }
    if (v >= 1000L)
    {
        return 4;
    }
    if (v >= 100L)
    {
        return 3;
    }
    if (v >= 10L)
    {
        return 2;
    }
    return 1;
}
static uint64_t div1e8(const uint64_t x)
{
    return x / 100000000;
}

static int32_t to_chars_df(const floating_decimal_64 v, const uint32_t olength, char *const result)
{
    /* Step 5: Print the decimal representation. */
    int32_t            index = 0;

    uint64_t       output = v.mantissa;
    int32_t        exp = v.exponent;
    uint32_t       output3 = 0;

    /*----
     * On entry, mantissa * 10^exp is the result to be output.
     * Caller has already done the - sign if needed.
     *
     * We want to insert the point somewhere depending on the output length
     * and exponent, which might mean adding zeros:
     *
     *            exp  | format
     *            1+   |  ddddddddd000000
     *            0    |  ddddddddd
     *  -1 .. -len+1   |  dddddddd.d to d.ddddddddd
     *  -len ...       |  0.ddddddddd to 0.000dddddd
     */
    uint32_t        i = 0;
    int32_t        nexp = exp + olength;

    if (nexp <= 0)
    {
        /* -nexp is number of 0s to add after '.' */
        /* 0.000ddddd */
        index = 2 - nexp;
        /* won't need more than this many 0s */
        rmemcpy1(result, 0, "0.000000", 8);
    }
    else if (exp < 0)
    {
        /*
         * dddd.dddd; leave space at the start and move the '.' in after
         */
        index = 1;
    }
    else
    {
        /*
         * We can save some code later by pre-filling with zeros. We know that
         * there can be no more than 16 output digits in this form, otherwise
         * we would not choose fixed-point output.
         */
        rmemset1(result, 0, '0', 16);
    }

    /*
     * We prefer 32-bit operations, even on 64-bit platforms. We have at most
     * 17 digits, and uint32_t can store 9 digits. If output doesn't fit into
     * uint32_t, we cut off 8 digits, so the rest will fit into uint32_t.
     */
    if ((output >> 32) != 0)
    {
        /* Expensive 64-bit division. */
        const uint64_t q = div1e8(output);
        uint32_t        output2 = (uint32_t) (output - 100000000 * q);
        const uint32_t c = output2 % 10000;

        output = q;
        output2 /= 10000;

        do
        {
            const uint32_t d = output2 % 10000;
            const uint32_t c0 = (c % 100) << 1;
            const uint32_t c1 = (c / 100) << 1;
            const uint32_t d0 = (d % 100) << 1;
            const uint32_t d1 = (d / 100) << 1;

            rmemcpy1(result + index + olength - i - 2, 0, DIGIT_TABLE + c0, 2);
            rmemcpy1(result + index + olength - i - 4, 0, DIGIT_TABLE + c1, 2);
            rmemcpy1(result + index + olength - i - 6, 0, DIGIT_TABLE + d0, 2);
            rmemcpy1(result + index + olength - i - 8, 0, DIGIT_TABLE + d1, 2);
            i += 8;
        } while (0);
    }

    output3 = (uint32_t) output;

    while (output3 >= 10000)
    {
        const uint32_t c = output3 - 10000 * (output3 / 10000);
        const uint32_t c0 = (c % 100) << 1;
        const uint32_t c1 = (c / 100) << 1;

        output3 /= 10000;
        rmemcpy1(result + index + olength - i - 2, 0, DIGIT_TABLE + c0, 2);
        rmemcpy1(result + index + olength - i - 4, 0, DIGIT_TABLE + c1, 2);
        i += 4;
    }
    if (output3 >= 100)
    {
        const uint32_t c = (output3 % 100) << 1;

        output3 /= 100;
        rmemcpy1(result + index + olength - i - 2, 0, DIGIT_TABLE + c, 2);
        i += 2;
    }
    if (output3 >= 10)
    {
        const uint32_t c = output3 << 1;

        rmemcpy1(result + index + olength - i - 2, 0, DIGIT_TABLE + c, 2);
    }
    else
    {
        result[index] = (char) ('0' + output3);
    }

    if (index == 1)
    {
        /*
         * nexp is 1..15 here, representing the number of digits before the
         * point. A value of 16 is not possible because we switch to
         * scientific notation when the display exponent reaches 15.
         */
        /* gcc only seems to want to optimize memmove for small 2^n */
        if (nexp & 8)
        {
            memmove(result + index - 1, result + index, 8);
            index += 8;
        }
        if (nexp & 4)
        {
            memmove(result + index - 1, result + index, 4);
            index += 4;
        }
        if (nexp & 2)
        {
            memmove(result + index - 1, result + index, 2);
            index += 2;
        }
        if (nexp & 1)
        {
            result[index - 1] = result[index];
        }
        result[nexp] = '.';
        index = olength + 1;
    }
    else if (exp >= 0)
    {
        /* we supplied the trailing zeros earlier, now just set the length. */
        index = olength + exp;
    }
    else
    {
        index = olength + (2 - nexp);
    }

    return index;
}

static int32_t to_chars_f(const floating_decimal_32 v, const uint32_t olength, char *const result)
{
    /* Step 5: Print the decimal representation. */
    int32_t            index = 0;

    uint32_t       output = v.mantissa;
    int32_t        exp = v.exponent;

    /*----
     * On entry, mantissa * 10^exp is the result to be output.
     * Caller has already done the - sign if needed.
     *
     * We want to insert the point somewhere depending on the output length
     * and exponent, which might mean adding zeros:
     *
     *            exp  | format
     *            1+   |  ddddddddd000000
     *            0    |  ddddddddd
     *  -1 .. -len+1   |  dddddddd.d to d.ddddddddd
     *  -len ...       |  0.ddddddddd to 0.000dddddd
     */
    uint32_t        i = 0;
    int32_t        nexp = exp + olength;

    if (nexp <= 0)
    {
        /* -nexp is number of 0s to add after '.' */
        /* 0.000ddddd */
        index = 2 - nexp;
        /* copy 8 bytes rather than 5 to let compiler optimize */
        rmemcpy1(result, 0, "0.000000", 8);
    }
    else if (exp < 0)
    {
        /*
         * dddd.dddd; leave space at the start and move the '.' in after
         */
        index = 1;
    }
    else
    {
        /*
         * We can save some code later by pre-filling with zeros. We know that
         * there can be no more than 6 output digits in this form, otherwise
         * we would not choose fixed-point output. memset 8 rather than 6
         * bytes to let the compiler optimize it.
         */
        rmemset1(result, 0, '0', 8);
    }

    while (output >= 10000)
    {
        const uint32_t c = output - 10000 * (output / 10000);
        const uint32_t c0 = (c % 100) << 1;
        const uint32_t c1 = (c / 100) << 1;

        output /= 10000;

        rmemcpy1(result + index + olength - i - 2, 0, DIGIT_TABLE + c0, 2);
        rmemcpy1(result + index + olength - i - 4, 0, DIGIT_TABLE + c1, 2);
        i += 4;
    }
    if (output >= 100)
    {
        const uint32_t c = (output % 100) << 1;

        output /= 100;
        rmemcpy1(result + index + olength - i - 2, 0, DIGIT_TABLE + c, 2);
        i += 2;
    }
    if (output >= 10)
    {
        const uint32_t c = output << 1;

        rmemcpy1(result + index + olength - i - 2, 0, DIGIT_TABLE + c, 2);
    }
    else
    {
        result[index] = (char) ('0' + output);
    }

    if (index == 1)
    {
        /*
         * nexp is 1..6 here, representing the number of digits before the
         * point. A value of 7+ is not possible because we switch to
         * scientific notation when the display exponent reaches 6.
         */
        /* gcc only seems to want to optimize memmove for small 2^n */
        if (nexp & 4)
        {
            memmove(result + index - 1, result + index, 4);
            index += 4;
        }
        if (nexp & 2)
        {
            memmove(result + index - 1, result + index, 2);
            index += 2;
        }
        if (nexp & 1)
        {
            result[index - 1] = result[index];
        }
        result[nexp] = '.';
        index = olength + 1;
    }
    else if (exp >= 0)
    {
        /* we supplied the trailing zeros earlier, now just set the length. */
        index = olength + exp;
    }
    else
    {
        index = olength + (2 - nexp);
    }

    return index;
}

static int32_t d_to_chars(floating_decimal_64 v, const bool sign, char *const result)
{
    /* Step 5: Print the decimal representation. */
    int32_t            index = 0;

    uint64_t        output = v.mantissa;
    uint32_t        olength = decimalLength(output);
    int32_t         exp = v.exponent + olength - 1;
    uint32_t        output3 = 0;
    uint32_t        i = 0;

    if (sign)
    {
        result[index++] = '-';
    }

    /*
     * The thresholds for fixed-point output are chosen to match printf
     * defaults. Beware that both the code of to_chars_df and the value of
     * DOUBLE_SHORTEST_DECIMAL_LEN are sensitive to these thresholds.
     */
    if (exp >= -4 && exp < 15)
        return to_chars_df(v, olength, result + index) + sign;

    /*
     * If v.exponent is exactly 0, we might have reached here via the small
     * integer fast path, in which case v.mantissa might contain trailing
     * (decimal) zeros. For scientific notation we need to move these zeros
     * into the exponent. (For fixed point this doesn't matter, which is why
     * we do this here rather than above.)
     *
     * Since we already calculated the display exponent (exp) above based on
     * the old decimal length, that value does not change here. Instead, we
     * just reduce the display length for each digit removed.
     *
     * If we didn't get here via the fast path, the raw exponent will not
     * usually be 0, and there will be no trailing zeros, so we pay no more
     * than one div10/multiply extra cost. We claw back half of that by
     * checking for divisibility by 2 before dividing by 10.
     */
    if (v.exponent == 0)
    {
        while ((output & 1) == 0)
        {
            const uint64_t q = div10(output);
            const uint32_t r = (uint32_t) (output - 10 * q);

            if (r != 0)
                break;
            output = q;
            --olength;
        }
    }

    /*----
     * Print the decimal digits.
     *
     * The following code is equivalent to:
     *
     * for (uint32_t i = 0; i < olength - 1; ++i) {
     *   const uint32_t c = output % 10; output /= 10;
     *   result[index + olength - i] = (char) ('0' + c);
     * }
     * result[index] = '0' + output % 10;
     *----
     */

    /*
     * We prefer 32-bit operations, even on 64-bit platforms. We have at most
     * 17 digits, and uint32_t can store 9 digits. If output doesn't fit into
     * uint32_t, we cut off 8 digits, so the rest will fit into uint32_t.
     */
    if ((output >> 32) != 0)
    {
        /* Expensive 64-bit division. */
        const uint64_t q = div1e8(output);
        uint32_t        output2 = (uint32_t) (output - 100000000 * q);
        const uint32_t c = output2 % 10000;

        output = q;
        output2 /= 10000;

        do
        {
            const uint32_t d = output2 % 10000;
            const uint32_t c0 = (c % 100) << 1;
            const uint32_t c1 = (c / 100) << 1;
            const uint32_t d0 = (d % 100) << 1;
            const uint32_t d1 = (d / 100) << 1;

            rmemcpy1(result + index + olength - i - 1, 0, DIGIT_TABLE + c0, 2);
            rmemcpy1(result + index + olength - i - 3, 0, DIGIT_TABLE + c1, 2);
            rmemcpy1(result + index + olength - i - 5, 0, DIGIT_TABLE + d0, 2);
            rmemcpy1(result + index + olength - i - 7, 0, DIGIT_TABLE + d1, 2);
            i += 8;
        } while (0);
    }

    output3 = (uint32_t) output;

    while (output3 >= 10000)
    {
        const uint32_t c = output3 - 10000 * (output3 / 10000);
        const uint32_t c0 = (c % 100) << 1;
        const uint32_t c1 = (c / 100) << 1;

        output3 /= 10000;

        rmemcpy1(result + index + olength - i - 1, 0, DIGIT_TABLE + c0, 2);
        rmemcpy1(result + index + olength - i - 3, 0, DIGIT_TABLE + c1, 2);
        i += 4;
    }
    if (output3 >= 100)
    {
        const uint32_t c = (output3 % 100) << 1;

        output3 /= 100;
        rmemcpy1(result + index + olength - i - 1, 0, DIGIT_TABLE + c, 2);
        i += 2;
    }
    if (output3 >= 10)
    {
        const uint32_t c = output3 << 1;

        /*
         * We can't use memcpy here: the decimal dot goes between these two
         * digits.
         */
        result[index + olength - i] = DIGIT_TABLE[c + 1];
        result[index] = DIGIT_TABLE[c];
    }
    else
    {
        result[index] = (char) ('0' + output3);
    }

    /* Print decimal point if needed. */
    if (olength > 1)
    {
        result[index + 1] = '.';
        index += olength + 1;
    }
    else
    {
        ++index;
    }

    /* Print the exponent. */
    result[index++] = 'e';
    if (exp < 0)
    {
        result[index++] = '-';
        exp = -exp;
    }
    else
        result[index++] = '+';

    if (exp >= 100)
    {
        const int32_t c = exp % 10;

        rmemcpy1(result + index, 0, DIGIT_TABLE + 2 * (exp / 10), 2);
        result[index + 2] = (char) ('0' + c);
        index += 3;
    }
    else
    {
        rmemcpy1(result + index, 0, DIGIT_TABLE + 2 * exp, 2);
        index += 2;
    }

    return index;
}

static int32_t f_to_chars(const floating_decimal_32 v, const bool sign, char *const result)
{
    /* Step 5: Print the decimal representation. */
    int32_t            index = 0;

    uint32_t       output = v.mantissa;
    uint32_t       olength = decimalLength(output);
    int32_t        exp = v.exponent + olength - 1;
    uint32_t        i = 0;

    if (sign)
        result[index++] = '-';

    /*
     * The thresholds for fixed-point output are chosen to match printf
     * defaults. Beware that both the code of to_chars_f and the value of
     * FLOAT_SHORTEST_DECIMAL_LEN are sensitive to these thresholds.
     */
    if (exp >= -4 && exp < 6)
        return to_chars_f(v, olength, result + index) + sign;

    /*
     * If v.exponent is exactly 0, we might have reached here via the small
     * integer fast path, in which case v.mantissa might contain trailing
     * (decimal) zeros. For scientific notation we need to move these zeros
     * into the exponent. (For fixed point this doesn't matter, which is why
     * we do this here rather than above.)
     *
     * Since we already calculated the display exponent (exp) above based on
     * the old decimal length, that value does not change here. Instead, we
     * just reduce the display length for each digit removed.
     *
     * If we didn't get here via the fast path, the raw exponent will not
     * usually be 0, and there will be no trailing zeros, so we pay no more
     * than one div10/multiply extra cost. We claw back half of that by
     * checking for divisibility by 2 before dividing by 10.
     */
    if (v.exponent == 0)
    {
        while ((output & 1) == 0)
        {
            const uint32_t q = output / 10;
            const uint32_t r = output - 10 * q;

            if (r != 0)
                break;
            output = q;
            --olength;
        }
    }

    /*----
     * Print the decimal digits.
     * The following code is equivalent to:
     *
     * for (uint32_t i = 0; i < olength - 1; ++i) {
     *   const uint32_t c = output % 10; output /= 10;
     *   result[index + olength - i] = (char) ('0' + c);
     * }
     * result[index] = '0' + output % 10;
     */

    while (output >= 10000)
    {
        const uint32_t c = output - 10000 * (output / 10000);
        const uint32_t c0 = (c % 100) << 1;
        const uint32_t c1 = (c / 100) << 1;

        output /= 10000;

        rmemcpy1(result + index + olength - i - 1, 0, DIGIT_TABLE + c0, 2);
        rmemcpy1(result + index + olength - i - 3, 0, DIGIT_TABLE + c1, 2);
        i += 4;
    }
    if (output >= 100)
    {
        const uint32_t c = (output % 100) << 1;

        output /= 100;
        rmemcpy1(result + index + olength - i - 1, 0, DIGIT_TABLE + c, 2);
        i += 2;
    }
    if (output >= 10)
    {
        const uint32_t c = output << 1;

        /*
         * We can't use memcpy here: the decimal dot goes between these two
         * digits.
         */
        result[index + olength - i] = DIGIT_TABLE[c + 1];
        result[index] = DIGIT_TABLE[c];
    }
    else
    {
        result[index] = (char) ('0' + output);
    }

    /* Print decimal point if needed. */
    if (olength > 1)
    {
        result[index + 1] = '.';
        index += olength + 1;
    }
    else
    {
        ++index;
    }

    /* Print the exponent. */
    result[index++] = 'e';
    if (exp < 0)
    {
        result[index++] = '-';
        exp = -exp;
    }
    else
        result[index++] = '+';

    rmemcpy1(result + index, 0, DIGIT_TABLE + 2 * exp, 2);
    index += 2;

    return index;
}

static int32_t float_to_shortest_decimal_bufn(float f, char *result)
{
    /*
     * Step 1: Decode the floating-point number, and unify normalized and
     * subnormal cases.
     */
    const uint32_t bits = float_to_bits(f);

    /* Decode bits into sign, mantissa, and exponent. */
    const bool    ieeeSign = ((bits >> (FLOAT_MANTISSA_BITS + FLOAT_EXPONENT_BITS)) & 1) != 0;
    const uint32_t ieeeMantissa = bits & ((1u << FLOAT_MANTISSA_BITS) - 1);
    const uint32_t ieeeExponent = (bits >> FLOAT_MANTISSA_BITS) & ((1u << FLOAT_EXPONENT_BITS) - 1);
    floating_decimal_32 v;
    bool    isSmallInt = false;

    /* Case distinction; exit early for the easy cases. */
    if (ieeeExponent == ((1u << FLOAT_EXPONENT_BITS) - 1u) || (ieeeExponent == 0 && ieeeMantissa == 0))
    {
        return copy_special_str(result, ieeeSign, (ieeeExponent != 0), (ieeeMantissa != 0));
    }

    isSmallInt = f2d_small_int(ieeeMantissa, ieeeExponent, &v);

    if (!isSmallInt)
    {
        v = f2d(ieeeMantissa, ieeeExponent);
    }

    return f_to_chars(v, ieeeSign, result);
}

static int32_t float_to_shortest_decimal_buf(float f, char *result)
{
    const int32_t index = float_to_shortest_decimal_bufn(f, result);

    /* Terminate the string. */
    result[index] = '\0';
    return index;
}

/*
 *        float4out        - converts a float4 number to a string
 *                          using a standard output format
 */
xk_pg_parser_Datum float4out(xk_pg_parser_Datum attr)
{
    float num = DatumGetFloat4(attr);
    char *ascii = NULL;
    int32_t   ndig = FLT_DIG + extra_float_digits;

    if(!xk_pg_parser_mcxt_malloc(PGFUNC_FLOAT_MCXT, (void **) &ascii, 32))
        return (xk_pg_parser_Datum) 0;

    if (extra_float_digits > 0)
    {
        float_to_shortest_decimal_buf(num, ascii);
        return (xk_pg_parser_Datum) ascii;
    }

    (void) xk_pg_parser_strfromd(ascii, 32, ndig, num);
    return (xk_pg_parser_Datum) ascii;
}

static bool d2d_small_int(const uint64_t ieeeMantissa,
                          const uint32_t ieeeExponent,
                          floating_decimal_64 *v)
{
    const int32_t e2 = (int32_t) ieeeExponent - DOUBLE_BIAS - DOUBLE_MANTISSA_BITS;

    /*
     * Avoid using multiple "return false;" here since it tends to provoke the
     * compiler into inlining multiple copies of d2d, which is undesirable.
     */

    if (e2 >= -DOUBLE_MANTISSA_BITS && e2 <= 0)
    {
        /*----
         * Since 2^52 <= m2 < 2^53 and 0 <= -e2 <= 52:
         *   1 <= f = m2 / 2^-e2 < 2^53.
         *
         * Test if the lower -e2 bits of the significand are 0, i.e. whether
         * the fraction is 0. We can use ieeeMantissa here, since the implied
         * 1 bit can never be tested by this; the implied 1 can only be part
         * of a fraction if e2 < -DOUBLE_MANTISSA_BITS which we already
         * checked. (e.g. 0.5 gives ieeeMantissa == 0 and e2 == -53)
         */
        const uint64_t mask = (XK_PG_PARSER_UINT64CONST(1) << -e2) - 1;
        const uint64_t fraction = ieeeMantissa & mask;

        if (fraction == 0)
        {
            /*----
             * f is an integer in the range [1, 2^53).
             * Note: mantissa might contain trailing (decimal) 0's.
             * Note: since 2^53 < 10^16, there is no need to adjust
             * decimalLength().
             */
            const uint64_t m2 = (XK_PG_PARSER_UINT64CONST(1) << DOUBLE_MANTISSA_BITS) | ieeeMantissa;

            v->mantissa = m2 >> -e2;
            v->exponent = 0;
            return true;
        }
    }

    return false;
}

static uint64_t mulShift64(const uint64_t m, const uint64_t *const mul, const int32_t j)
{
    const __uint128_t b0 = ((__uint128_t) m) * mul[0];
    const __uint128_t b2 = ((__uint128_t) m) * mul[1];

    return (uint64_t) (((b0 >> 64) + b2) >> (j - 64));
}

static uint64_t mulShiftAll(const uint64_t m, const uint64_t *const mul, const int32_t j,
                            uint64_t *const vp, uint64_t *const vm, const uint32_t mmShift)
{
    *vp = mulShift64(4 * m + 2, mul, j);
    *vm = mulShift64(4 * m - 1 - mmShift, mul, j);
    return mulShift64(4 * m, mul, j);
}

static uint64_t div5(const uint64_t x)
{
    return x / 5;
}

static uint64_t div10(const uint64_t x)
{
    return x / 10;
}

static uint64_t div100(const uint64_t x)
{
    return x / 100;
}

static floating_decimal_64 d2d(const uint64_t ieeeMantissa, const uint32_t ieeeExponent)
{
    int32_t        e2 = (ieeeExponent == 0 ? e2 = 1 - DOUBLE_BIAS - DOUBLE_MANTISSA_BITS - 2 : ieeeExponent - DOUBLE_BIAS - DOUBLE_MANTISSA_BITS - 2);
    uint64_t        m2 = (ieeeExponent == 0 ? ieeeMantissa : (XK_PG_PARSER_UINT64CONST(1) << DOUBLE_MANTISSA_BITS) | ieeeMantissa);

#if STRICTLY_SHORTEST
    const bool    even = (m2 & 1) == 0;
    const bool    acceptBounds = even;
#else
    const bool    acceptBounds = false;
#endif

    /* Step 2: Determine the interval of legal decimal representations. */
    const uint64_t mv = 4 * m2;

    /* Implicit bool -> int32_t conversion. True is 1, false is 0. */
    const uint32_t mmShift = ieeeMantissa != 0 || ieeeExponent <= 1;

    /* We would compute mp and mm like this: */
    /* uint64_t mp = 4 * m2 + 2; */
    /* uint64_t mm = mv - 1 - mmShift; */

    /* Step 3: Convert to a decimal power base using 128-bit arithmetic. */
    uint64_t        vr,
                vp,
                vm;
    int32_t        e10;
    bool        vmIsTrailingZeros = false;
    bool        vrIsTrailingZeros = false;
    uint32_t        removed = 0;
    uint8_t        lastRemovedDigit = 0;
    uint64_t        output;

    floating_decimal_64 fd;

    if (e2 >= 0)
    {
        /*
         * I tried special-casing q == 0, but there was no effect on
         * performance.
         *
         * This expr is slightly faster than max(0, log10Pow2(e2) - 1).
         */
        const uint32_t q = log10Pow2(e2) - (e2 > 3);
        const int32_t k = DOUBLE_POW5_INV_BITCOUNT + pow5bits(q) - 1;
        const int32_t i = -e2 + q + k;

        e10 = q;

        vr = mulShiftAll(m2, DOUBLE_POW5_INV_SPLIT[q], i, &vp, &vm, mmShift);

        if (q <= 21)
        {
            /*
             * This should use q <= 22, but I think 21 is also safe. Smaller
             * values may still be safe, but it's more difficult to reason
             * about them.
             *
             * Only one of mp, mv, and mm can be a multiple of 5, if any.
             */
            const uint32_t mvMod5 = (uint32_t) (mv - 5 * div5(mv));

            if (mvMod5 == 0)
            {
                vrIsTrailingZeros = multipleOfPowerOf5(mv, q);
            }
            else if (acceptBounds)
            {
                /*----
                 * Same as min(e2 + (~mm & 1), pow5Factor(mm)) >= q
                 * <=> e2 + (~mm & 1) >= q && pow5Factor(mm) >= q
                 * <=> true && pow5Factor(mm) >= q, since e2 >= q.
                 *----
                 */
                vmIsTrailingZeros = multipleOfPowerOf5(mv - 1 - mmShift, q);
            }
            else
            {
                /* Same as min(e2 + 1, pow5Factor(mp)) >= q. */
                vp -= multipleOfPowerOf5(mv + 2, q);
            }
        }
    }
    else
    {
        /*
         * This expression is slightly faster than max(0, log10Pow5(-e2) - 1).
         */
        const uint32_t q = log10Pow5(-e2) - (-e2 > 1);
        const int32_t i = -e2 - q;
        const int32_t k = pow5bits(i) - DOUBLE_POW5_BITCOUNT;
        const int32_t j = q - k;

        e10 = q + e2;

        vr = mulShiftAll(m2, DOUBLE_POW5_SPLIT[i], j, &vp, &vm, mmShift);

        if (q <= 1)
        {
            /*
             * {vr,vp,vm} is trailing zeros if {mv,mp,mm} has at least q
             * trailing 0 bits.
             */
            /* mv = 4 * m2, so it always has at least two trailing 0 bits. */
            vrIsTrailingZeros = true;
            if (acceptBounds)
            {
                /*
                 * mm = mv - 1 - mmShift, so it has 1 trailing 0 bit iff
                 * mmShift == 1.
                 */
                vmIsTrailingZeros = mmShift == 1;
            }
            else
            {
                /*
                 * mp = mv + 2, so it always has at least one trailing 0 bit.
                 */
                --vp;
            }
        }
        else if (q < 63)
        {
            /* TODO(ulfjack):Use a tighter bound here. */
            /*
             * We need to compute min(ntz(mv), pow5Factor(mv) - e2) >= q - 1
             */
            /* <=> ntz(mv) >= q - 1 && pow5Factor(mv) - e2 >= q - 1 */
            /* <=> ntz(mv) >= q - 1 (e2 is negative and -e2 >= q) */
            /* <=> (mv & ((1 << (q - 1)) - 1)) == 0 */

            /*
             * We also need to make sure that the left shift does not
             * overflow.
             */
            vrIsTrailingZeros = multipleOfPowerOf2(mv, q - 1);
        }
    }

    /*
     * Step 4: Find the shortest decimal representation in the interval of
     * legal representations.
     */
    /* On average, we remove ~2 digits. */
    if (vmIsTrailingZeros || vrIsTrailingZeros)
    {
        /* General case, which happens rarely (~0.7%). */
        for (;;)
        {
            const uint64_t vpDiv10 = div10(vp);
            const uint64_t vmDiv10 = div10(vm);

            const uint32_t vmMod10 = (uint32_t) (vm - 10 * vmDiv10);
            const uint64_t vrDiv10 = div10(vr);
            const uint32_t vrMod10 = (uint32_t) (vr - 10 * vrDiv10);

            if (vpDiv10 <= vmDiv10)
                break;

            vmIsTrailingZeros &= vmMod10 == 0;
            vrIsTrailingZeros &= lastRemovedDigit == 0;
            lastRemovedDigit = (uint8_t) vrMod10;
            vr = vrDiv10;
            vp = vpDiv10;
            vm = vmDiv10;
            ++removed;
        }

        if (vmIsTrailingZeros)
        {
            for (;;)
            {
                const uint64_t vmDiv10 = div10(vm);
                const uint32_t vmMod10 = (uint32_t) (vm - 10 * vmDiv10);

                const uint64_t vpDiv10 = div10(vp);
                const uint64_t vrDiv10 = div10(vr);
                const uint32_t vrMod10 = (uint32_t) (vr - 10 * vrDiv10);

                if (vmMod10 != 0)
                    break;

                vrIsTrailingZeros &= lastRemovedDigit == 0;
                lastRemovedDigit = (uint8_t) vrMod10;
                vr = vrDiv10;
                vp = vpDiv10;
                vm = vmDiv10;
                ++removed;
            }
        }

        if (vrIsTrailingZeros && lastRemovedDigit == 5 && vr % 2 == 0)
        {
            /* Round even if the exact number is .....50..0. */
            lastRemovedDigit = 4;
        }

        /*
         * We need to take vr + 1 if vr is outside bounds or we need to round
         * up.
         */
        output = vr + ((vr == vm && (!acceptBounds || !vmIsTrailingZeros)) || lastRemovedDigit >= 5);
    }
    else
    {
        /*
         * Specialized for the common case (~99.3%). Percentages below are
         * relative to this.
         */
        bool        roundUp = false;
        const uint64_t vpDiv100 = div100(vp);
        const uint64_t vmDiv100 = div100(vm);

        if (vpDiv100 > vmDiv100)
        {
            /* Optimization:remove two digits at a time(~86.2 %). */
            const uint64_t vrDiv100 = div100(vr);
            const uint32_t vrMod100 = (uint32_t) (vr - 100 * vrDiv100);

            roundUp = vrMod100 >= 50;
            vr = vrDiv100;
            vp = vpDiv100;
            vm = vmDiv100;
            removed += 2;
        }

        /*----
         * Loop iterations below (approximately), without optimization
         * above:
         *
         * 0: 0.03%, 1: 13.8%, 2: 70.6%, 3: 14.0%, 4: 1.40%, 5: 0.14%,
         * 6+: 0.02%
         *
         * Loop iterations below (approximately), with optimization
         * above:
         *
         * 0: 70.6%, 1: 27.8%, 2: 1.40%, 3: 0.14%, 4+: 0.02%
         *----
         */
        for (;;)
        {
            const uint64_t vpDiv10 = div10(vp);
            const uint64_t vmDiv10 = div10(vm);

            const uint64_t vrDiv10 = div10(vr);
            const uint32_t vrMod10 = (uint32_t) (vr - 10 * vrDiv10);

            if (vpDiv10 <= vmDiv10)
                break;

            roundUp = vrMod10 >= 5;
            vr = vrDiv10;
            vp = vpDiv10;
            vm = vmDiv10;
            ++removed;
        }

        /*
         * We need to take vr + 1 if vr is outside bounds or we need to round
         * up.
         */
        output = vr + (vr == vm || roundUp);
    }

    do
    {
        const int32_t exp = e10 + removed;

        fd.exponent = exp;
        fd.mantissa = output;
    } while (0);

    return fd;
}

static uint64_t double_to_bits(const double d)
{
    uint64_t bits = 0;

    rmemcpy1(&bits, 0, &d, sizeof(double));
    return bits;
}

/*
 * Store the shortest decimal representation of the given double as an
 * UNTERMINATED string in the caller's supplied buffer (which must be at least
 * DOUBLE_SHORTEST_DECIMAL_LEN-1 bytes long).
 *
 * Returns the number of bytes stored.
 */
static int32_t double_to_shortest_decimal_bufn(double f, char *result)
{
    /*
     * Step 1: Decode the floating-point number, and unify normalized and
     * subnormal cases.
     */
    const uint64_t bits = double_to_bits(f);

    /* Decode bits into sign, mantissa, and exponent. */
    const bool    ieeeSign = ((bits >> (DOUBLE_MANTISSA_BITS + DOUBLE_EXPONENT_BITS)) & 1) != 0;
    const uint64_t ieeeMantissa = bits & ((XK_PG_PARSER_UINT64CONST(1) << DOUBLE_MANTISSA_BITS) - 1);
    const uint32_t ieeeExponent = (uint32_t) ((bits >> DOUBLE_MANTISSA_BITS) & ((1u << DOUBLE_EXPONENT_BITS) - 1));

    floating_decimal_64 v;
    bool    isSmallInt = false;

    /* Case distinction; exit early for the easy cases. */
    if (ieeeExponent == ((1u << DOUBLE_EXPONENT_BITS) - 1u) || (ieeeExponent == 0 && ieeeMantissa == 0))
    {
        return copy_special_str(result, ieeeSign, (ieeeExponent != 0), (ieeeMantissa != 0));
    }

    isSmallInt = d2d_small_int(ieeeMantissa, ieeeExponent, &v);

    if (!isSmallInt)
    {
        v = d2d(ieeeMantissa, ieeeExponent);
    }

    return d_to_chars(v, ieeeSign, result);
}

static int32_t double_to_shortest_decimal_buf(double f, char *result)
{
    const int32_t index = double_to_shortest_decimal_bufn(f, result);

    /* Terminate the string. */
    result[index] = '\0';
    return index;
}

/*
 * float8out_internal - guts of float8out()
 *
 * This is exposed for use by functions that want a reasonably
 * platform-independent way of outputting doubles.
 * The result is always palloc'd.
 */
char *float8out_internal(double num)
{
    char *ascii = NULL;
    int32_t ndig = DBL_DIG + extra_float_digits;

    if(!xk_pg_parser_mcxt_malloc(PGFUNC_FLOAT_MCXT, (void **) &ascii, 32))
        return (xk_pg_parser_Datum) 0;

    if (extra_float_digits > 0)
    {
        double_to_shortest_decimal_buf(num, ascii);
        return ascii;
    }

    (void) xk_pg_parser_strfromd(ascii, 32, ndig, num);
    return ascii;
}

static inline double xk_pg_parser_DatumGetFloat8(xk_pg_parser_Datum X)
{
    union
    {
        int64_t        value;
        double         retval;
    }myunion;

    myunion.value = (int64_t)(X);
    return myunion.retval;
}

/*
 *        float8out        - converts float8 number to a string
 *                          using a standard output format
 */
xk_pg_parser_Datum float8out(xk_pg_parser_Datum attr)
{
    double num = xk_pg_parser_DatumGetFloat8(attr);

    return (xk_pg_parser_Datum) float8out_internal(num);
}
